python - <<'PY'
import os, json, itertools
out={'files':{},'diagnostics':{},'samples':{}}
for fn in ['model.py','predict.py','train.py','val_eval.py','probe_qwen.py']:
    try:
        txt=open(fn).read()
        out['files'][fn]=txt
    except Exception as e:
        out['files'][fn]='ERR '+repr(e)
for fn in ['logs/iter_25/native_diag.json','logs/iter_26/inspect_current.json','logs/iter_23/module_diag.json','logs/iter_22/peft_diag.json']:
    try:
        out['diagnostics'][fn]=json.load(open(fn))
    except Exception as e:
        out['diagnostics'][fn]='ERR '+repr(e)
for fn in ['logs/val_eval_qwen_base.jsonl','logs/val_eval_rescaled.jsonl','logs/probe_qwen_rescaled.jsonl','logs/probe_qwen.jsonl']:
    rows=[]
    try:
        with open(fn) as f:
            for line in itertools.islice(f, 20):
                if line.strip(): rows.append(json.loads(line))
    except Exception as e:
        rows='ERR '+repr(e)
    out['samples'][fn]=rows
# dataset stats and example rows
for fn in ['/data/unified_train.jsonl','/data/unified_val.jsonl']:
    stats={'n':0,'bbox':0,'point':0,'both':0,'types':{},'examples':[]}
    try:
        with open(fn) as f:
            for line in f:
                if not line.strip(): continue
                r=json.loads(line); stats['n']+=1
                hb=bool(r.get('target_bbox')); hp=bool(r.get('target_point'))
                stats['bbox']+=hb; stats['point']+=hp; stats['both']+=hb and hp
                stats['types'][r.get('type','')]=stats['types'].get(r.get('type',''),0)+1
                if len(stats['examples'])<8: stats['examples'].append(r)
    except Exception as e:
        stats={'err':repr(e)}
    out['diagnostics'][fn]=stats
os.makedirs('logs/iter_'+os.environ.get('RAB_ITERATION','27'), exist_ok=True)
path='logs/iter_'+os.environ.get('RAB_ITERATION','27')+'/late_inspect.json'
with open(path,'w') as f: json.dump(out,f,indent=2,default=str)
print(json.dumps({'wrote':path,'file_lens':{k:len(v) for k,v in out['files'].items()},'val_sample_count':len(out['samples'].get('logs/val_eval_qwen_base.jsonl',[]))},indent=2))
PY
